using Heathen.SteamworksIntegration;
using UnityEngine;
using System.Collections.Generic;

namespace SteamTools
{
    public static class Game
    {
        // Generated by SteamToolsSettings

#if APP4543970
        public const uint AppId = 4543970;
#elif APP0
        public const uint AppId = 0;
#else
        public const uint AppId = 0;
#endif
        // Default server configuration
        public static SteamGameServerConfiguration ServerConfiguration = new()
        {
            autoInitialise = false,
            autoLogon = false,
            ip = 0,
            gamePort = 0,
            queryPort = 0,
            spectatorPort = 0,
            serverVersion = "",
            usingGameServerAuthApi = false,
            enableHeartbeats = false,
            supportSpectators = false,
            spectatorServerName = "",
            anonymousServerLogin = false,
            gameServerToken = "",
            isPasswordProtected = false,
            serverName = "",
            gameDescription = "",
            gameDirectory = "",
            isDedicated = false,
            maxPlayerCount = 0,
            botPlayerCount = 0,
            mapName = "",
            gameData = "",
            rulePairs = null
        };

        public static void ServerConfigFromIni(string iniData) => ServerConfiguration = SteamGameServerConfiguration.ParseIniString(iniData);
        public static void ServerConfigFromJson(string jsonData) => ServerConfiguration = JsonUtility.FromJson<SteamGameServerConfiguration>(jsonData);
        private static bool _initialised;

        public static void Initialise()
        {
               if (_initialised) return;

               _initialised = true;

              Interface.Initialise();

              Debug.Log($"Initialising for app {AppId}");
              SteamTools.Events.OnSteamInitialised += HandleInitialised;
#if UNITY_SERVER
              Heathen.SteamworksIntegration.API.App.Server.Initialise(AppId, ServerConfiguration);
#else
             List<InputActionData> actions = new();

#if APP4543970
#elif APP0
#endif

             Heathen.SteamworksIntegration.API.App.Client.Initialise(AppId, actions.ToArray());
#endif
        }

        private static void HandleInitialised()
        {
                Dictionary<string, LeaderboardData> boardMap = new();
                Dictionary<string, InputActionSetData> setMap = new();
                Dictionary<string, InputActionData> actionMap = new();
                Interface.RaiseOnReady(boardMap, setMap, actionMap);
        }
    }
}
